// Controller for file uploads
@RestController
@RequestMapping("/api")
class FileUploadController {

    private final Path fileStorageLocation;
    private final String fileUrlPath;
    private static final List<String> ALLOWED_IMAGE_TYPES = Arrays.asList(
            MediaType.IMAGE_JPEG_VALUE,
            MediaType.IMAGE_PNG_VALUE,
            MediaType.IMAGE_GIF_VALUE,
            "image/bmp",
            "image/webp"
    );

    public FileUploadController(FileStorageProperties fileStorageProperties) throws IOException {
        this.fileStorageLocation = Paths.get(fileStorageProperties.getDir())
                .toAbsolutePath().normalize();
        this.fileUrlPath = fileStorageProperties.getUrlPath();

        try {
            Files.createDirectories(this.fileStorageLocation);
        } catch (IOException ex) {
            throw new IOException("Could not create the directory where the uploaded files will be stored.", ex);
        }
    }

    @PostMapping("/upload/profile-picture")
    public ResponseEntity<UploadFileResponse> uploadProfilePicture(@RequestParam("file") MultipartFile file) {
        // Validate file presence
        if (file.isEmpty()) {
            return new ResponseEntity("Please select a file to upload.", HttpStatus.BAD_REQUEST);
        }

        // Validate file type
        String contentType = file.getContentType();
        if (contentType == null || !ALLOWED_IMAGE_TYPES.contains(contentType)) {
            return new ResponseEntity("Invalid file type. Only common image formats are allowed.", HttpStatus.BAD_REQUEST);
        }

        // Generate unique file name
        String originalFileName = Objects.requireNonNull(file.getOriginalFilename());
        String fileExtension = "";
        int dotIndex = originalFileName.lastIndexOf('.');
        if (dotIndex > 0) {
            fileExtension = originalFileName.substring(dotIndex);
        }
        String fileName = UUID.randomUUID().toString() + fileExtension;

        try {
            // Copy file to the target location (Replacing existing file with the same name)
            Path targetLocation = this.fileStorageLocation.resolve(fileName);
            Files.copy(file.getInputStream(), targetLocation, StandardCopyOption.REPLACE_EXISTING);

            String fileDownloadUri = ServletUriComponentsBuilder.fromCurrentContextPath()
                    .path(fileUrlPath)
                    .path(fileName)
                    .toUriString();

            return ResponseEntity.ok(new UploadFileResponse(fileName, fileDownloadUri, file.getContentType(), file.getSize()));
        } catch (IOException ex) {
            return new ResponseEntity("Could not store file " + fileName + ". Please try again! " + ex.getMessage(), HttpStatus.INTERNAL_SERVER_ERROR);
        }
    }
}